var zlib = require('zlib');

var weekData = $('Fetch Week').first().json;
var courseData = $('Fetch Course').first().json;

var moduleName = courseData.module_name || 'Course';
var moduleCode = courseData.module_code || '';
var weekNum = weekData.week_number || 1;
var topic = weekData.topic || 'Untitled';

function parseArr(d) {
  if (!d) return [];
  if (Array.isArray(d)) return d.map(String);
  if (typeof d === 'string') { try { var p = JSON.parse(d); return Array.isArray(p) ? p.map(String) : [d]; } catch(e) { return [d]; } }
  return [];
}

var objectives = parseArr(weekData.learning_objectives);
var prompts = parseArr(weekData.discussion_prompts);
var activities = parseArr(weekData.activity_ideas);
var teachingNotes = weekData.teaching_notes || '';
var teachingMethods = weekData.teaching_methods || '';

function esc(s) { return String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;'); }

// ---- Build slides ----
var slides = [];

// Slide 1: Title
slides.push('<p:sld xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" xmlns:p="http://schemas.openxmlformats.org/presentationml/2006/main"><p:cSld><p:bg><p:bgPr><a:solidFill><a:srgbClr val="1E3A5F"/></a:solidFill><a:effectLst/></p:bgPr></p:bg><p:spTree><p:nvGrpSpPr><p:cNvPr id="1" name=""/><p:cNvGrpSpPr/><p:nvPr/></p:nvGrpSpPr><p:grpSpPr/>' +
'<p:sp><p:nvSpPr><p:cNvPr id="2" name="code"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="914400" y="1371600"/><a:ext cx="7315200" cy="457200"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:noFill/></p:spPr><p:txBody><a:bodyPr/><a:lstStyle/><a:p><a:r><a:rPr lang="en-US" sz="1800" dirty="0"><a:solidFill><a:srgbClr val="A0C4E8"/></a:solidFill></a:rPr><a:t>' + esc(moduleCode) + '</a:t></a:r></a:p></p:txBody></p:sp>' +
'<p:sp><p:nvSpPr><p:cNvPr id="3" name="title"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="914400" y="1828800"/><a:ext cx="7315200" cy="914400"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:noFill/></p:spPr><p:txBody><a:bodyPr/><a:lstStyle/><a:p><a:r><a:rPr lang="en-US" sz="3200" b="1" dirty="0"><a:solidFill><a:srgbClr val="FFFFFF"/></a:solidFill></a:rPr><a:t>' + esc(moduleName) + '</a:t></a:r></a:p></p:txBody></p:sp>' +
'<p:sp><p:nvSpPr><p:cNvPr id="4" name="week"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="914400" y="3200400"/><a:ext cx="7315200" cy="457200"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:noFill/></p:spPr><p:txBody><a:bodyPr/><a:lstStyle/><a:p><a:r><a:rPr lang="en-US" sz="2000" dirty="0"><a:solidFill><a:srgbClr val="A0C4E8"/></a:solidFill></a:rPr><a:t>Week ' + weekNum + '</a:t></a:r></a:p></p:txBody></p:sp>' +
'<p:sp><p:nvSpPr><p:cNvPr id="5" name="topic"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="914400" y="3657600"/><a:ext cx="7315200" cy="914400"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:noFill/></p:spPr><p:txBody><a:bodyPr/><a:lstStyle/><a:p><a:r><a:rPr lang="en-US" sz="2400" b="1" dirty="0"><a:solidFill><a:srgbClr val="FFFFFF"/></a:solidFill></a:rPr><a:t>' + esc(topic) + '</a:t></a:r></a:p></p:txBody></p:sp>' +
'</p:spTree></p:cSld></p:sld>');

// Helper: bullet slide
function bulletSlide(title, items, bgColor, titleColor, bulletColor) {
  var bullets = '';
  for (var i = 0; i < items.length; i++) {
    bullets += '<a:p><a:pPr marL="342900" indent="-342900"><a:buChar char="&#x2022;"/></a:pPr><a:r><a:rPr lang="en-US" sz="1600" dirty="0"><a:solidFill><a:srgbClr val="333333"/></a:solidFill></a:rPr><a:t>' + esc(items[i]) + '</a:t></a:r></a:p>';
  }
  return '<p:sld xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" xmlns:p="http://schemas.openxmlformats.org/presentationml/2006/main"><p:cSld><p:bg><p:bgPr><a:solidFill><a:srgbClr val="FFFFFF"/></a:solidFill><a:effectLst/></p:bgPr></p:bg><p:spTree><p:nvGrpSpPr><p:cNvPr id="1" name=""/><p:cNvGrpSpPr/><p:nvPr/></p:nvGrpSpPr><p:grpSpPr/>' +
  '<p:sp><p:nvSpPr><p:cNvPr id="2" name="bar"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="9144000" cy="1097280"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:solidFill><a:srgbClr val="' + titleColor + '"/></a:solidFill></p:spPr><p:txBody><a:bodyPr anchor="ctr"/><a:lstStyle/><a:p><a:pPr marL="457200"/><a:r><a:rPr lang="en-US" sz="2800" b="1" dirty="0"><a:solidFill><a:srgbClr val="FFFFFF"/></a:solidFill></a:rPr><a:t>' + esc(title) + '</a:t></a:r></a:p></p:txBody></p:sp>' +
  '<p:sp><p:nvSpPr><p:cNvPr id="3" name="body"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="457200" y="1371600"/><a:ext cx="8229600" cy="4800600"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:noFill/></p:spPr><p:txBody><a:bodyPr wrap="square"/><a:lstStyle/>' + bullets + '</p:txBody></p:sp>' +
  '</p:spTree></p:cSld></p:sld>';
}

// Helper: text slide
function textSlide(title, text, titleColor) {
  return '<p:sld xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" xmlns:p="http://schemas.openxmlformats.org/presentationml/2006/main"><p:cSld><p:bg><p:bgPr><a:solidFill><a:srgbClr val="FFFFFF"/></a:solidFill><a:effectLst/></p:bgPr></p:bg><p:spTree><p:nvGrpSpPr><p:cNvPr id="1" name=""/><p:cNvGrpSpPr/><p:nvPr/></p:nvGrpSpPr><p:grpSpPr/>' +
  '<p:sp><p:nvSpPr><p:cNvPr id="2" name="bar"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="0" y="0"/><a:ext cx="9144000" cy="1097280"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:solidFill><a:srgbClr val="' + titleColor + '"/></a:solidFill></p:spPr><p:txBody><a:bodyPr anchor="ctr"/><a:lstStyle/><a:p><a:pPr marL="457200"/><a:r><a:rPr lang="en-US" sz="2800" b="1" dirty="0"><a:solidFill><a:srgbClr val="FFFFFF"/></a:solidFill></a:rPr><a:t>' + esc(title) + '</a:t></a:r></a:p></p:txBody></p:sp>' +
  '<p:sp><p:nvSpPr><p:cNvPr id="3" name="body"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="457200" y="1371600"/><a:ext cx="8229600" cy="4800600"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:noFill/></p:spPr><p:txBody><a:bodyPr wrap="square"/><a:lstStyle/><a:p><a:r><a:rPr lang="en-US" sz="1500" dirty="0"><a:solidFill><a:srgbClr val="333333"/></a:solidFill></a:rPr><a:t>' + esc(text) + '</a:t></a:r></a:p></p:txBody></p:sp>' +
  '</p:spTree></p:cSld></p:sld>';
}

// Slide 2: Learning Objectives
if (objectives.length > 0) slides.push(bulletSlide('Learning Objectives', objectives, 'FFFFFF', '27AE60', '27AE60'));

// Slide 3: Discussion Topics
if (prompts.length > 0) slides.push(bulletSlide('Discussion Topics', prompts, 'FFFFFF', '2B6CB0', '2B6CB0'));

// Slide 4: Teaching Strategy
if (teachingNotes) slides.push(textSlide('Teaching Strategy', teachingNotes, '8E44AD'));

// Slide 5: Teaching Method
if (teachingMethods) slides.push(textSlide('Teaching Method', teachingMethods, '6C3483'));

// Slide 6: Activities
if (activities.length > 0) slides.push(bulletSlide('Activities', activities, 'FFFFFF', 'E67E22', 'E67E22'));

// Slide 7: Summary
var summaryBullets = objectives.slice(0, 5);
if (summaryBullets.length > 0) {
  var sumBullets = '';
  for (var i = 0; i < summaryBullets.length; i++) {
    sumBullets += '<a:p><a:pPr marL="342900" indent="-342900"><a:buChar char="&#x2713;"/></a:pPr><a:r><a:rPr lang="en-US" sz="1600" dirty="0"><a:solidFill><a:srgbClr val="FFFFFF"/></a:solidFill></a:rPr><a:t>' + esc(summaryBullets[i]) + '</a:t></a:r></a:p>';
  }
  slides.push('<p:sld xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" xmlns:p="http://schemas.openxmlformats.org/presentationml/2006/main"><p:cSld><p:bg><p:bgPr><a:solidFill><a:srgbClr val="1E3A5F"/></a:solidFill><a:effectLst/></p:bgPr></p:bg><p:spTree><p:nvGrpSpPr><p:cNvPr id="1" name=""/><p:cNvGrpSpPr/><p:nvPr/></p:nvGrpSpPr><p:grpSpPr/>' +
  '<p:sp><p:nvSpPr><p:cNvPr id="2" name="t"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="914400" y="1371600"/><a:ext cx="7315200" cy="914400"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:noFill/></p:spPr><p:txBody><a:bodyPr/><a:lstStyle/><a:p><a:pPr algn="ctr"/><a:r><a:rPr lang="en-US" sz="3200" b="1" dirty="0"><a:solidFill><a:srgbClr val="FFFFFF"/></a:solidFill></a:rPr><a:t>Key Takeaways</a:t></a:r></a:p></p:txBody></p:sp>' +
  '<p:sp><p:nvSpPr><p:cNvPr id="3" name="b"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="1371600" y="2514600"/><a:ext cx="6400800" cy="3200400"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:noFill/></p:spPr><p:txBody><a:bodyPr wrap="square"/><a:lstStyle/>' + sumBullets + '</p:txBody></p:sp>' +
  '<p:sp><p:nvSpPr><p:cNvPr id="4" name="f"/><p:cNvSpPr/><p:nvPr/></p:nvSpPr><p:spPr><a:xfrm><a:off x="914400" y="6172200"/><a:ext cx="7315200" cy="365760"/></a:xfrm><a:prstGeom prst="rect"><a:avLst/></a:prstGeom><a:noFill/></p:spPr><p:txBody><a:bodyPr/><a:lstStyle/><a:p><a:pPr algn="ctr"/><a:r><a:rPr lang="en-US" sz="1100" dirty="0"><a:solidFill><a:srgbClr val="88AACC"/></a:solidFill></a:rPr><a:t>' + esc(moduleCode + ' | ' + moduleName + ' | Week ' + weekNum) + '</a:t></a:r></a:p></p:txBody></p:sp>' +
  '</p:spTree></p:cSld></p:sld>');
}

// ---- Build PPTX (ZIP) ----
var slideCount = slides.length;

// Relationships for slides in presentation.xml.rels
var presRels = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">';
for (var i = 0; i < slideCount; i++) {
  presRels += '<Relationship Id="rId' + (i+1) + '" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/slide" Target="slides/slide' + (i+1) + '.xml"/>';
}
presRels += '<Relationship Id="rId' + (slideCount+1) + '" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/theme" Target="theme/theme1.xml"/>';
presRels += '</Relationships>';

// presentation.xml
var presXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?><p:presentation xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships" xmlns:p="http://schemas.openxmlformats.org/presentationml/2006/main"><p:sldMasterIdLst/><p:sldIdLst>';
for (var i = 0; i < slideCount; i++) {
  presXml += '<p:sldId id="' + (256+i) + '" r:id="rId' + (i+1) + '"/>';
}
presXml += '</p:sldIdLst><p:sldSz cx="9144000" cy="6858000" type="screen4x3"/><p:notesSz cx="6858000" cy="9144000"/></p:presentation>';

// [Content_Types].xml
var contentTypes = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="xml" ContentType="application/xml"/><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Override PartName="/ppt/presentation.xml" ContentType="application/vnd.openxmlformats-officedocument.presentationml.presentation.main+xml"/><Override PartName="/ppt/theme/theme1.xml" ContentType="application/vnd.openxmlformats-officedocument.theme+xml"/>';
for (var i = 0; i < slideCount; i++) {
  contentTypes += '<Override PartName="/ppt/slides/slide' + (i+1) + '.xml" ContentType="application/vnd.openxmlformats-officedocument.presentationml.slide+xml"/>';
}
contentTypes += '</Types>';

// _rels/.rels
var rootRels = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="ppt/presentation.xml"/></Relationships>';

// theme1.xml (minimal)
var themeXml = '<?xml version="1.0" encoding="UTF-8" standalone="yes"?><a:theme xmlns:a="http://schemas.openxmlformats.org/drawingml/2006/main" name="Theme"><a:themeElements><a:clrScheme name="Custom"><a:dk1><a:srgbClr val="000000"/></a:dk1><a:lt1><a:srgbClr val="FFFFFF"/></a:lt1><a:dk2><a:srgbClr val="1E3A5F"/></a:dk2><a:lt2><a:srgbClr val="E7E6E6"/></a:lt2><a:accent1><a:srgbClr val="2B6CB0"/></a:accent1><a:accent2><a:srgbClr val="27AE60"/></a:accent2><a:accent3><a:srgbClr val="E67E22"/></a:accent3><a:accent4><a:srgbClr val="8E44AD"/></a:accent4><a:accent5><a:srgbClr val="2980B9"/></a:accent5><a:accent6><a:srgbClr val="1ABC9C"/></a:accent6><a:hlink><a:srgbClr val="0563C1"/></a:hlink><a:folHlink><a:srgbClr val="954F72"/></a:folHlink></a:clrScheme><a:fontScheme name="Custom"><a:majorFont><a:latin typeface="Calibri"/><a:ea typeface=""/><a:cs typeface=""/></a:majorFont><a:minorFont><a:latin typeface="Calibri"/><a:ea typeface=""/><a:cs typeface=""/></a:minorFont></a:fontScheme><a:fmtScheme name="Custom"><a:fillStyleLst><a:solidFill><a:schemeClr val="phClr"/></a:solidFill><a:solidFill><a:schemeClr val="phClr"/></a:solidFill><a:solidFill><a:schemeClr val="phClr"/></a:solidFill></a:fillStyleLst><a:lnStyleLst><a:ln w="6350"><a:solidFill><a:schemeClr val="phClr"/></a:solidFill></a:ln><a:ln w="6350"><a:solidFill><a:schemeClr val="phClr"/></a:solidFill></a:ln><a:ln w="6350"><a:solidFill><a:schemeClr val="phClr"/></a:solidFill></a:ln></a:lnStyleLst><a:effectStyleLst><a:effectStyle><a:effectLst/></a:effectStyle><a:effectStyle><a:effectLst/></a:effectStyle><a:effectStyle><a:effectLst/></a:effectStyle></a:effectStyleLst><a:bgFillStyleLst><a:solidFill><a:schemeClr val="phClr"/></a:solidFill><a:solidFill><a:schemeClr val="phClr"/></a:solidFill><a:solidFill><a:schemeClr val="phClr"/></a:solidFill></a:bgFillStyleLst></a:fmtScheme></a:themeElements></a:theme>';

// ---- Minimal ZIP builder (store method, no compression) ----
var files = [];
files.push({ name: '[Content_Types].xml', data: Buffer.from(contentTypes, 'utf8') });
files.push({ name: '_rels/.rels', data: Buffer.from(rootRels, 'utf8') });
files.push({ name: 'ppt/presentation.xml', data: Buffer.from(presXml, 'utf8') });
files.push({ name: 'ppt/_rels/presentation.xml.rels', data: Buffer.from(presRels, 'utf8') });
files.push({ name: 'ppt/theme/theme1.xml', data: Buffer.from(themeXml, 'utf8') });
for (var i = 0; i < slideCount; i++) {
  files.push({ name: 'ppt/slides/slide' + (i+1) + '.xml', data: Buffer.from(slides[i], 'utf8') });
}

// ZIP format: local file headers + data, then central directory, then end record
var localHeaders = [];
var centralHeaders = [];
var offset = 0;

for (var i = 0; i < files.length; i++) {
  var f = files[i];
  var nameBytes = Buffer.from(f.name, 'utf8');
  var crc = crc32(f.data);
  var size = f.data.length;

  // Local file header (30 bytes + name + data)
  var local = Buffer.alloc(30 + nameBytes.length);
  local.writeUInt32LE(0x04034b50, 0); // signature
  local.writeUInt16LE(20, 4); // version needed
  local.writeUInt16LE(0, 6); // flags
  local.writeUInt16LE(0, 8); // compression: stored
  local.writeUInt16LE(0, 10); // mod time
  local.writeUInt16LE(0, 12); // mod date
  local.writeUInt32LE(crc, 14); // crc32
  local.writeUInt32LE(size, 18); // compressed size
  local.writeUInt32LE(size, 22); // uncompressed size
  local.writeUInt16LE(nameBytes.length, 26); // name length
  local.writeUInt16LE(0, 28); // extra length
  nameBytes.copy(local, 30);

  localHeaders.push(Buffer.concat([local, f.data]));

  // Central directory header (46 bytes + name)
  var central = Buffer.alloc(46 + nameBytes.length);
  central.writeUInt32LE(0x02014b50, 0); // signature
  central.writeUInt16LE(20, 4); // version made by
  central.writeUInt16LE(20, 6); // version needed
  central.writeUInt16LE(0, 8); // flags
  central.writeUInt16LE(0, 10); // compression
  central.writeUInt16LE(0, 12); // mod time
  central.writeUInt16LE(0, 14); // mod date
  central.writeUInt32LE(crc, 16); // crc32
  central.writeUInt32LE(size, 20); // compressed size
  central.writeUInt32LE(size, 24); // uncompressed size
  central.writeUInt16LE(nameBytes.length, 28); // name length
  central.writeUInt16LE(0, 30); // extra length
  central.writeUInt16LE(0, 32); // comment length
  central.writeUInt16LE(0, 34); // disk number start
  central.writeUInt16LE(0, 36); // internal attrs
  central.writeUInt32LE(0, 38); // external attrs
  central.writeUInt32LE(offset, 42); // local header offset
  nameBytes.copy(central, 46);

  centralHeaders.push(central);
  offset += 30 + nameBytes.length + size;
}

// CRC32 function
function crc32(buf) {
  var table = [];
  for (var n = 0; n < 256; n++) {
    var c = n;
    for (var k = 0; k < 8; k++) { c = (c & 1) ? (0xEDB88320 ^ (c >>> 1)) : (c >>> 1); }
    table[n] = c;
  }
  var crc = 0xFFFFFFFF;
  for (var i = 0; i < buf.length; i++) { crc = table[(crc ^ buf[i]) & 0xFF] ^ (crc >>> 8); }
  return (crc ^ 0xFFFFFFFF) >>> 0;
}

var localData = Buffer.concat(localHeaders);
var centralData = Buffer.concat(centralHeaders);

// End of central directory (22 bytes)
var endRecord = Buffer.alloc(22);
endRecord.writeUInt32LE(0x06054b50, 0);
endRecord.writeUInt16LE(0, 4); // disk number
endRecord.writeUInt16LE(0, 6); // disk with central dir
endRecord.writeUInt16LE(files.length, 8); // entries on disk
endRecord.writeUInt16LE(files.length, 10); // total entries
endRecord.writeUInt32LE(centralData.length, 12); // central dir size
endRecord.writeUInt32LE(localData.length, 16); // central dir offset
endRecord.writeUInt16LE(0, 20); // comment length

var zipBuffer = Buffer.concat([localData, centralData, endRecord]);
var base64 = zipBuffer.toString('base64');

var fileName = (moduleCode || 'course').replace(/[^a-zA-Z0-9]/g,'_') + '_Week_' + weekNum + '.pptx';

return [{json: { pptxBase64: base64, fileName: fileName, mimeType: 'application/vnd.openxmlformats-officedocument.presentationml.presentation' }}];

parameters.jsCode:
const items = $input.all();
const item = items[0].json;
const base64 = item.pptxBase64;
const fileName = item.fileName || 'slides.pptx';
const mimeType = item.mimeType || 'application/vnd.openxmlformats-officedocument.presentationml.presentation';

const pptxBuffer = Buffer.from(base64, 'base64');
const binaryData = await this.helpers.prepareBinaryData(pptxBuffer, fileName, mimeType);

return [{
  json: { fileName },
  binary: { data: binaryData }
}];
